DROP TABLE IF EXISTS `leave_balances`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `leave_balances` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned NOT NULL,
  `leave_type_id` bigint(20) unsigned NOT NULL,
  `year` int(10) unsigned NOT NULL,
  `opening_balance` int(11) NOT NULL DEFAULT 0,
  `entitlement` int(11) NOT NULL DEFAULT 0,
  `carry_forward` int(11) NOT NULL DEFAULT 0,
  `adjustment_plus` int(11) NOT NULL DEFAULT 0,
  `adjustment_minus` int(11) NOT NULL DEFAULT 0,
  `used_days` int(11) NOT NULL DEFAULT 0,
  `reserved_days` int(11) NOT NULL DEFAULT 0,
  `remaining_balance` int(11) NOT NULL DEFAULT 0,
  `meta_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`meta_json`)),
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `leave_balances_user_type_year_unique` (`user_id`,`leave_type_id`,`year`)
) ENGINE=InnoDB AUTO_INCREMENT=92 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
