  KEY `rnah_approver_fk` (`approver_id`),
  CONSTRAINT `rnah_approval_fk` FOREIGN KEY (`rapat_notulensi_approval_id`) REFERENCES `rapat_notulensi_approvals` (`id`) ON DELETE CASCADE,
  CONSTRAINT `rnah_approver_fk` FOREIGN KEY (`approver_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `rnah_notulensi_fk` FOREIGN KEY (`rapat_notulensi_id`) REFERENCES `rapat_notulensis` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
