INSERT INTO `rapat_notulensis` VALUES (1,1,10,10,10,'template_a','selesai',0,'Rapat Monitoring dan Evaluasi Bidang Kesekretariatan','<p><strong>Hari/Tanggal/Jam</strong> : Senin, 23 Maret 2026 / 09:42 WIT s.d. selesai</p><p><strong>Tempat</strong> : PTA Papua Barat</p><p><strong>Pimpinan Agenda</strong> : Sekretaris</p><p><strong>Peserta yang Diundang</strong> : Kabag Kepegawaian, Kabag Umum, Operator Surat Masuk, Staf Kepaniteraan 1</p>','<ol><li><a href=\"https://www.google.com/search?q=Zona+Integritas+%28ZI%29&amp;rlz=1C1UEAD_enID1088ID1088&amp;oq=apa+itu+zi&amp;gs_lcrp=EgZjaHJvbWUyBggAEEUYOTIHCAEQABiABDINCAIQABiDARixAxiABDIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIHCAcQABiABDIHCAgQABiABDIHCAkQABiABNIBCDE0MTVqMGo3qAIAsAIA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwivipiq57STAxVt-DgGHSnVESMQgK4QegYIAQgAEAM\">Zona Integritas (ZI)</a> adalah predikat yang diberikan kepada instansi pemerintah di Indonesia yang pimpinan dan jajarannya berkomitmen mewujudkan Wilayah Bebas dari Korupsi (WBK) dan Wilayah Birokrasi Bersih dan Melayani (WBBM). ZI berfokus pada reformasi birokrasi, pencegahan korupsi, dan peningkatan kualitas pelayanan publik.</li><li><a href=\"https://www.google.com/search?q=Zona+Integritas+%28ZI%29&amp;rlz=1C1UEAD_enID1088ID1088&amp;oq=apa+itu+zi&amp;gs_lcrp=EgZjaHJvbWUyBggAEEUYOTIHCAEQABiABDINCAIQABiDARixAxiABDIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIHCAcQABiABDIHCAgQABiABDIHCAkQABiABNIBCDE0MTVqMGo3qAIAsAIA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwivipiq57STAxVt-DgGHSnVESMQgK4QegYIAQgAEAM\">Zona Integritas (ZI)</a> adalah predikat yang diberikan kepada instansi pemerintah di Indonesia yang pimpinan dan jajarannya berkomitmen mewujudkan Wilayah Bebas dari Korupsi (WBK) dan Wilayah Birokrasi Bersih dan Melayani (WBBM). ZI berfokus pada reformasi birokrasi, pencegahan korupsi, dan peningkatan kualitas pelayanan publik.</li><li><a href=\"https://www.google.com/search?q=Zona+Integritas+%28ZI%29&amp;rlz=1C1UEAD_enID1088ID1088&amp;oq=a