--
-- Table structure for table `surat_keluars`
--

DROP TABLE IF EXISTS `surat_keluars`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `surat_keluars` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `legacy_source_id` bigint(20) unsigned DEFAULT NULL,
  `nomor_surat` varchar(255) NOT NULL,
  `nomor_urut` int(11) NOT NULL,
  `tahun_surat` year(4) NOT NULL,
  `klasifikasi_kode_id` bigint(20) unsigned NOT NULL,
  `kategori_surat_id` bigint(20) unsigned DEFAULT NULL,
  `kode_fungsi_id` bigint(20) unsigned DEFAULT NULL,
  `kode_kegiatan_id` bigint(20) unsigned DEFAULT NULL,
  `kode_transaksi_id` bigint(20) unsigned DEFAULT NULL,
  `nomenklatur_jabatan` enum('ketua','wakil_ketua','sekretaris','panitera') NOT NULL,
  `opsi_penerima` enum('internal','external') NOT NULL,
  `penerima_external` varchar(255) DEFAULT NULL,
  `perihal` text NOT NULL,
  `tanggal_surat` date NOT NULL,
  `has_lampiran` tinyint(1) NOT NULL DEFAULT 0,
  `file_path` varchar(255) DEFAULT NULL,
  `status` enum('draft','lengkap') NOT NULL DEFAULT 'draft',
  `created_by` bigint(20) unsigned NOT NULL,
  `rapat_id` bigint(20) unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `surat_keluars_nomor_surat_unique` (`nomor_surat`),
  UNIQUE KEY `surat_keluars_rapat_id_unique` (`rapat_id`),
  UNIQUE KEY `surat_keluars_legacy_source_id_unique` (`legacy_source_id`),
  KEY `surat_keluars_klasifikasi_kode_id_foreign` (`klasifikasi_kode_id`),
  KEY `surat_keluars_kode_fungsi_id_foreign` (`kode_fungsi_id`),
  KEY `surat_keluars_kode_kegiatan_id_foreign` (`kode_kegiatan_id`),
  KEY `surat_keluars_kode_transaksi_id_foreign` (`kode_transaksi_id`),
  KEY `surat_keluars_created_by_foreign` (`created_by`),
  KEY `surat_keluars_kategori_surat_id_foreign` (`kategori_surat_id`),
  CONSTRAINT `surat_keluars_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `surat_keluars_kategori_surat_id_foreign` FOREIGN KEY (`kategori_surat_id`) REFERENCES `kategori_surats` (`id`) ON DELETE SET NULL,
  CONSTRAINT `surat_keluars_klasifikasi_kode_id_foreign` FOREIGN KEY (`klasifikasi_kode_id`) REFERENCES `klasifikasi_kodes` (`id`),
  CONSTRAINT `surat_keluars_kode_fungsi_id_foreign` FOREIGN KEY (`kode_fungsi_id`) REFERENCES `klasifikasi_kodes` (`id`),
  CONSTRAINT `surat_keluars_kode_kegiatan_id_foreign` FOREIGN KEY (`kode_kegiatan_id`) REFERENCES `klasifikasi_kodes` (`id`),
  CONSTRAINT `surat_keluars_kode_transaksi_id_foreign` FOREIGN KEY (`kode_transaksi_id`) REFERENCES `klasifikasi_kodes` (`id`),
  CONSTRAINT `surat_keluars_rapat_id_foreign` FOREIGN KEY (`rapat_id`) REFERENCES `rapats` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=3055 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

