--
-- Table structure for table `surat_masuks`
--

DROP TABLE IF EXISTS `surat_masuks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `surat_masuks` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `legacy_source_id` bigint(20) unsigned DEFAULT NULL,
  `nomor_surat` varchar(255) NOT NULL,
  `opsi_pengirim` enum('mahkamah_agung','non_mahkamah_agung') NOT NULL,
  `klasifikasi_kode_id` bigint(20) unsigned DEFAULT NULL,
  `kategori_surat_id` bigint(20) unsigned DEFAULT NULL,
  `pengirim` varchar(255) NOT NULL,
  `perihal` text NOT NULL,
  `tanggal_surat` date NOT NULL,
  `sifat` enum('biasa','rahasia','sangat_rahasia') NOT NULL DEFAULT 'biasa',
  `file_path` varchar(255) NOT NULL,
  `status` enum('baru','didisposisi','selesai') NOT NULL DEFAULT 'baru',
  `created_by` bigint(20) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `surat_masuks_legacy_source_id_unique` (`legacy_source_id`),
  KEY `surat_masuks_klasifikasi_kode_id_foreign` (`klasifikasi_kode_id`),
  KEY `surat_masuks_created_by_foreign` (`created_by`),
  KEY `surat_masuks_kategori_surat_id_foreign` (`kategori_surat_id`),
  CONSTRAINT `surat_masuks_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `surat_masuks_kategori_surat_id_foreign` FOREIGN KEY (`kategori_surat_id`) REFERENCES `kategori_surats` (`id`) ON DELETE SET NULL,
  CONSTRAINT `surat_masuks_klasifikasi_kode_id_foreign` FOREIGN KEY (`klasifikasi_kode_id`) REFERENCES `klasifikasi_kodes` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1208 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `surat_masuks`
--

LOCK TABLES `surat_masuks` WRITE;
