INSERT INTO `surat_templates` VALUES (1,'Surat Tugas','surat-tugas','Penugasan','Template untuk penugasan resmi pegawai pada kegiatan atau perjalanan dinas tertentu.','active','[{\"name\":\"nomor_surat\",\"label\":\"Nomor Surat\",\"type\":\"text\",\"required\":true},{\"name\":\"tanggal_surat\",\"label\":\"Tanggal Surat\",\"type\":\"date\",\"required\":true},{\"name\":\"dasar_penugasan\",\"label\":\"Dasar Penugasan\",\"type\":\"textarea\",\"required\":true},{\"name\":\"nama_petugas\",\"label\":\"Nama Petugas\",\"type\":\"text\",\"required\":true},{\"name\":\"nip_petugas\",\"label\":\"NIP Petugas\",\"type\":\"text\",\"required\":false},{\"name\":\"jabatan_petugas\",\"label\":\"Jabatan Petugas\",\"type\":\"text\",\"required\":true},{\"name\":\"tujuan_tugas\",\"label\":\"Tujuan Tugas\",\"type\":\"textarea\",\"required\":true},{\"name\":\"tempat_tugas\",\"label\":\"Tempat Tugas\",\"type\":\"text\",\"required\":true},{\"name\":\"tanggal_mulai\",\"label\":\"Tanggal Mulai\",\"type\":\"date\",\"required\":true},{\"name\":\"tanggal_selesai\",\"label\":\"Tanggal Selesai\",\"type\":\"date\",\"required\":true}]','<p><strong>SURAT TUGAS</strong></p><p>Nomor: {{nomor_surat}}</p><p>Berdasarkan {{dasar_penugasan}}, dengan ini menugaskan:</p><p>Nama: <strong>{{nama_petugas}}</strong><br>NIP: {{nip_petugas}}<br>Jabatan: {{jabatan_petugas}}</p><p>Untuk melaksanakan tugas: {{tujuan_tugas}}</p><p>Tempat: {{tempat_tugas}}<br>Waktu: {{tanggal_mulai}} s.d. {{tanggal_selesai}}</p><p>Demikian surat tugas ini dibuat untuk dilaksanakan sebagaimana mestinya.</p><p>Manokwari, {{tanggal_surat}}</p>',NULL,'system',NULL,NULL,NULL,NULL,'2026-03-23 07:12:57','2026-03-23 07:12:57','2026-03-23 07:12:57'),(2,'Surat Keterangan','surat-keterangan','Keterangan','Template surat keterangan umum untuk kebutuhan kepegawaian dan administrasi internal.','active','[{\"name\":\"nomor_surat\",\"label\":\"Nomor Surat\",\"type\":\"text\",\"required\":true},{\"name\":\"tanggal_surat\",\"label\":\"Tanggal Surat\",\"type\":\"date\",\"required\":true},{\"name\":\"nama_pegawai\",\"label\":\"Nama Pegawai\",\"type\":\"text\",\"required\":true},{\"name\":\"nip_pegawai\",\"label\":\"NIP Pegawai\",\"type\":\"text\",\"required\":false},{\"name\":\"jabatan_pegawai\",\"label\":\"Jabatan Pegawai\",\"type\":\"text\",\"required\":true},{\"name\":\"isi_keterangan\",\"label\":\"Isi Keterangan\",\"type\":\"textarea\",\"required\":true},{\"name\":\"keperluan\",\"label\":\"Keperluan\",\"type\":\"textarea\",\"required\":true}]','<p><strong>SURAT KETERANGAN</strong></p><p>Nomor: {{nomor_surat}}</p><p>Yang bertanda tangan di bawah ini menerangkan bahwa:</p><p>Nama: <strong>{{nama_pegawai}}</strong><br>NIP: {{nip_pegawai}}<br>Jabatan: {{jabatan_pegawai}}</p><p>{{isi_keterangan}}</p><p>Surat ini dipergunakan untuk: {{keperluan}}</p><p>Manokwari, {{tanggal_surat}}</p>',NULL,'system',NULL,NULL,NULL,NULL,'2026-03-23 07:12:57','2026-03-23 07:12:57','2026-03-23 07:12:57'),(3,'Surat Perintah','surat-perintah','Instruksi','Template surat perintah internal dengan fokus pada instruksi pelaksanaan pekerjaan atau kegiatan.','active','[{\"name\":\"nomor_surat\",\"label\":\"Nomor Surat\",\"type\":\"text\",\"required\":true},{\"name\":\"tanggal_surat\",\"label\":\"Tanggal Surat\",\"type\":\"date\",\"required\":true},{\"name\":\"nama_pelaksana\",\"label\":\"Nama Pelaksana\",\"type\":\"text\",\"required\":true},{\"name\":\"jabatan_pelaksana\",\"label\":\"Jabatan Pelaksana\",\"type\":\"text\",\"required\":true},{\"name\":\"uraian_perintah\",\"label\":\"Uraian Perintah\",\"type\":\"textarea\",\"required\":true},{\"name\":\"target_waktu\",\"label\":\"Target Waktu\",\"type\":\"text\",\"required\":true}]','<p><strong>SURAT PERINTAH</strong></p><p>Nomor: {{nomor_surat}}</p><p>Kepada: <strong>{{nama_pelaksana}}</strong><br>Jabatan: {{jabatan_pelaksana}}</p><p>Dengan ini diperintahkan untuk melaksanakan: {{uraian_perintah}}</p><p>Target waktu pelaksanaan: {{target_waktu}}</p><p>Demikian untuk dilaksanakan dengan penuh tanggung jawab.</p><p>Manokwari, {{tanggal_surat}}</p>',NULL,'system',NULL,NULL,NULL,NULL,'2026-03-23 07:12:57','2026-03-23 07:12:57','2026-03-23 07:12:57');
