INSERT INTO `zi_guideline_indicators` VALUES (1,1,'1','Tim pembangunan Zona Integritas telah dibentuk dan ditetapkan di dalam unit kerja.','SK Tim ZI, surat keputusan pembentukan tim, surat tugas anggota tim.','Gunakan eviden dari surat keluar seperti SK Tim ZI atau surat tugas pembentukan tim kerja.',1,1,'2026-03-25 07:32:31','2026-03-25 11:37:21'),(2,2,'1','Terdapat pembagian tugas, penanggung jawab, dan forum koordinasi rutin tim kerja.','Notulen rapat tim, surat tugas, daftar tugas anggota, laporan tindak lanjut rapat.','Tautkan eviden rapat koordinasi, notulensi, dan laporan tindak lanjut bila tersedia.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(3,3,'1','Tersedia dokumen rencana kerja atau roadmap pembangunan Zona Integritas yang digunakan sebagai acuan pelaksanaan.','Roadmap ZI, program kerja, matriks tindak lanjut area perubahan.','Dokumen ini dapat diunggah manual atau dihubungkan dari surat/rapat yang membahas rencana kerja.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(4,4,'1','Peta proses bisnis tersedia dan menjadi referensi pelaksanaan tugas pada unit kerja.','Dokumen peta proses bisnis, keputusan penetapan, bahan sosialisasi internal.','Gunakan eviden surat edaran, sosialisasi, atau dokumen manual yang telah disahkan.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(5,5,'1','SOP utama tersedia, ditetapkan, dan digunakan dalam pelaksanaan layanan atau administrasi internal.','Dokumen SOP, berita acara reviu, notulensi sosialisasi SOP.','Tautkan notulensi rapat sosialisasi SOP atau surat keputusan penetapan SOP bila tersedia.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(6,6,'1','Terdapat pemanfaatan aplikasi atau sistem informasi dalam pengelolaan persuratan, rapat, kepegawaian, atau layanan internal lainnya.','Screenshot aplikasi, surat edaran penerapan sistem, laporan monitoring penggunaan sistem.','Modul persuratan, rapat, dan cuti pada aplikasi ini dapat dijadikan data dukung implementasi TI.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(7,7,'1','Pengajuan, persetujuan, dan pemantauan layanan kepegawaian seperti cuti atau penugasan pegawai terdokumentasi dengan baik.','Data cuti, surat tugas pegawai, laporan monitoring layanan kepegawaian.','Gunakan data dari modul cuti dan surat tugas sebagai eviden otomatis atau data pendukung.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(8,8,'1','Terdapat penugasan, pelatihan, atau kegiatan pembinaan yang terdokumentasi sebagai bagian pengembangan kompetensi.','Surat tugas, undangan, absensi, notulensi, sertifikat, atau laporan pelaksanaan kegiatan.','Integrasikan surat tugas dan rapat pembinaan untuk mengurangi input ganda.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(9,9,'1','Tersedia dokumen perencanaan kinerja yang dipakai dalam pelaksanaan dan pengukuran capaian.','Dokumen perjanjian kinerja, rencana aksi, matriks target.','Bisa diunggah manual atau dihubungkan dari surat keputusan/rapat pembahasan kinerja.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(10,10,'1','Terdapat eviden rapat monitoring atau evaluasi yang menghasilkan tindak lanjut perbaikan.','Undangan rapat, absensi, notulensi, laporan tindak lanjut.','Manfaatkan modul rapat untuk menarik eviden otomatis monitoring dan evaluasi.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(11,11,'1','Terdapat kebijakan atau surat edaran yang mengatur pengendalian internal, gratifikasi, atau benturan kepentingan.','Surat edaran, keputusan, bahan sosialisasi, dokumentasi rapat.','Gunakan surat keluar dan rapat sosialisasi sebagai eviden utama.',1,1,'2026-03-25 07:32:31','2026-03-25 11:48:46'),(12,12,'1','Terdapat surat, disposisi, rapat, atau laporan tindak lanjut atas hasil pengawasan dan arahan pimpinan.','Disposisi, surat tindak lanjut, notulensi rapat, laporan progres.','Modul persuratan dan rapat dapat dihubungkan langsung sebagai eviden tindak lanjut.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(13,13,'1','Dokumen standar pelayanan tersedia, dipublikasikan, dan dapat diakses oleh pengguna layanan.','Standar pelayanan, surat keputusan, dokumentasi publikasi.','Dokumen standar layanan dapat diunggah manual atau dihubungkan dari surat keputusan penetapannya.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(14,14,'1','Terdapat eviden rapat evaluasi, monitoring layanan, atau tindak lanjut peningkatan kualitas pelayanan publik.','Undangan rapat, absensi, notulensi evaluasi, laporan tindak lanjut, surat edaran perbaikan layanan.','Tarik eviden dari rapat monitoring/evaluasi dan surat tindak lanjut pelayanan untuk mengisi indikator ini.',0,1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(15,15,'1','Indikator dummy untuk perencanaan dan pelaksanaan penguatan tata kelola internal.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(16,16,'1','Indikator dummy untuk evaluasi berkala penguatan tata kelola internal.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',1,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(17,17,'1','Indikator dummy untuk perencanaan dan pelaksanaan penguatan disiplin kinerja.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(18,18,'1','Indikator dummy untuk evaluasi berkala penguatan disiplin kinerja.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',1,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(19,19,'1','Indikator dummy untuk perencanaan dan pelaksanaan digitalisasi administrasi.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(20,20,'1','Indikator dummy untuk evaluasi berkala digitalisasi administrasi.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',1,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(21,21,'1','Indikator dummy untuk perencanaan dan pelaksanaan integrasi pengawasan.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(22,22,'1','Indikator dummy untuk evaluasi berkala integrasi pengawasan.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',1,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(23,23,'1','Indikator dummy untuk perencanaan dan pelaksanaan sinergi tim lintas fungsi.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(24,24,'1','Indikator dummy untuk evaluasi berkala sinergi tim lintas fungsi.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',1,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(25,25,'1','Indikator dummy untuk perencanaan dan pelaksanaan inovasi proses kerja.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(26,26,'1','Indikator dummy untuk evaluasi berkala inovasi proses kerja.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',1,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(27,27,'1','Indikator dummy untuk perencanaan dan pelaksanaan capaian reformasi birokrasi.','Notulen rapat, foto kegiatan, dan rekap tindak lanjut.','Digunakan sebagai data contoh untuk pengembangan tampilan.',0,1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(28,28,'1','Indikator dummy untuk evaluasi berkala capaian reformasi birokrasi.','Notulen rapat, foto kegi