INSERT INTO `zi_guideline_points` VALUES (1,1,'I','Penyusunan Tim Kerja','Patokan awal pembentukan tim kerja pembangunan Zona Integritas pada unit kerja.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(2,1,'II','Penyusunan Rencana Pembangunan Zona Integritas','Rencana kerja menjadi acuan pelaksanaan program per area perubahan.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(3,2,'I','Proses Bisnis dan SOP','Penataan tatalaksana menekankan standar proses kerja yang terdokumentasi dan dijalankan.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(4,2,'II','Pemanfaatan Teknologi Informasi','Penggunaan TI dipakai untuk mendukung efektivitas proses kerja dan layanan.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(5,3,'I','Penataan Manajemen SDM','Area ini menekankan tertib administrasi kepegawaian dan pengelolaan SDM berbasis kebutuhan organisasi.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(6,4,'I','Perencanaan dan Pelaporan Kinerja','Akuntabilitas dibangun melalui perencanaan kinerja yang jelas dan tindak lanjut pemantauan berkala.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(7,5,'I','Pengendalian dan Tindak Lanjut Pengawasan','Penguatan pengawasan memerlukan mekanisme kebijakan, sosialisasi, dan tindak lanjut yang terdokumentasi.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(8,6,'I','Standar dan Evaluasi Pelayanan Publik','Area pelayanan publik menekankan standar layanan, evaluasi, dan tindak lanjut perbaikan layanan.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(9,7,'I','Penguatan Penguatan tata kelola internal','Poin pedoman dummy untuk reform tata kelola internal.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(10,8,'I','Penguatan Penguatan disiplin kinerja','Poin pedoman dummy untuk reform penguatan disiplin kinerja.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(11,9,'I','Penguatan Digitalisasi administrasi','Poin pedoman dummy untuk reform digitalisasi administrasi.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(12,10,'I','Penguatan Integrasi pengawasan','Poin pedoman dummy untuk reform integrasi pengawasan.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(13,11,'I','Penguatan Sinergi tim lintas fungsi','Poin pedoman dummy untuk reform sinergi tim lintas fungsi.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(14,12,'I','Penguatan Inovasi proses kerja','Poin pedoman dummy untuk reform inovasi proses kerja.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(15,13,'I','Penguatan Capaian reformasi birokrasi','Poin pedoman dummy untuk hasil capaian reformasi birokrasi.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(16,14,'I','Penguatan Dampak layanan publik','Poin pedoman dummy untuk hasil dampak layanan publik.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04');
