INSERT INTO `zi_guideline_sub_points` VALUES (1,1,'a','Unit kerja telah membentuk tim untuk melakukan pembangunan Zona Integritas.','Pembentukan tim menjadi dasar awal pelaksanaan program kerja dan koordinasi lintas unit.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(2,1,'b','Pembagian peran tim dan mekanisme koordinasi telah ditetapkan.','Tim yang dibentuk perlu memiliki pembagian tugas dan pola koordinasi yang jelas.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(3,2,'a','Unit kerja memiliki rencana kerja pembangunan Zona Integritas.','Rencana kerja minimal memuat target, jadwal, PIC, dan eviden yang dibutuhkan.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(4,3,'a','Proses bisnis utama unit kerja telah dipetakan.','Peta proses bisnis perlu menunjukkan alur kerja dan keterkaitan antar layanan.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(5,3,'b','SOP layanan utama telah disusun atau direviu.','SOP harus relevan dengan layanan aktual dan dipahami petugas.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(6,4,'a','Layanan administrasi internal telah memanfaatkan aplikasi atau sistem elektronik.','Pemanfaatan TI harus terlihat pada proses kerja yang berjalan, bukan hanya rencana.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(7,5,'a','Administrasi layanan kepegawaian berjalan tertib dan terdokumentasi.','Kedisiplinan administratif menjadi bagian penting dalam penataan SDM.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(8,5,'b','Pengembangan kompetensi pegawai ditindaklanjuti melalui penugasan atau kegiatan peningkatan kapasitas.','Pengembangan kompetensi harus terlihat pada eviden penugasan, pelatihan, atau kegiatan pembinaan.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(9,6,'a','Dokumen perencanaan kinerja tersedia dan digunakan sebagai acuan pelaksanaan.','Dokumen perencanaan harus menjadi dasar monitoring target dan capaian.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(10,6,'b','Monitoring dan evaluasi capaian dilaksanakan secara periodik.','Kegiatan monitoring harus menghasilkan catatan tindak lanjut yang jelas.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(11,7,'a','Kebijakan pengendalian internal, gratifikasi, atau benturan kepentingan tersedia.','Kebijakan perlu ditetapkan dan diketahui oleh unit kerja.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(12,7,'b','Tindak lanjut hasil pengawasan atau arahan pimpinan terdokumentasi.','Arah tindak lanjut perlu jelas dan dapat ditelusuri evidennya.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(13,8,'a','Standar pelayanan tersedia dan dipublikasikan.','Standar layanan menjadi referensi pemberian layanan yang konsisten.',1,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(14,8,'b','Evaluasi pelayanan dilakukan dan menghasilkan perbaikan layanan.','Kegiatan evaluasi harus terlihat tindak lanjutnya, bukan hanya dokumentasi rapat.',2,'2026-03-25 07:32:31','2026-03-25 07:32:31'),(15,9,'a','Perencanaan dan pelaksanaan penguatan tata kelola internal','Sub poin dummy untuk memastikan ada data monitoring pada area ini.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(16,9,'b','Evaluasi berkala penguatan tata kelola internal','Sub poin dummy lanjutan untuk pengisian data dashboard.',2,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(17,10,'a','Perencanaan dan pelaksanaan penguatan disiplin kinerja','Sub poin dummy untuk memastikan ada data monitoring pada area ini.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(18,10,'b','Evaluasi berkala penguatan disiplin kinerja','Sub poin dummy lanjutan untuk pengisian data dashboard.',2,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(19,11,'a','Perencanaan dan pelaksanaan digitalisasi administrasi','Sub poin dummy untuk memastikan ada data monitoring pada area ini.',1,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(20,11,'b','Evaluasi berkala digitalisasi administrasi','Sub poin dummy lanjutan untuk pengisian data dashboard.',2,'2026-04-21 01:35:04','2026-04-21 01:35:04'),(21,12,'a','Perencanaan dan pelaksanaan integrasi pengawasan